import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None  # No customers left to visit, might need to rest or end the route

    distances = np.linalg.norm(unvisited_customers - cur_truck_pos, axis=1)
    next_customer_index = np.argmin(distances)

    # Check if other trucks are closer to this customer
    for other_truck_pos in all_truck_pos:
        if not np.array_equal(other_truck_pos, cur_truck_pos):
            other_distances = np.linalg.norm(unvisited_customers - other_truck_pos, axis=1)
            if other_distances[next_customer_index] < distances[next_customer_index]:
                return None  # Let other truck handle this customer if it's closer

    best_node = next_customer_index
    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(a, b):
        return np.linalg.norm(a - b)

    best_node = None
    best_distance = np.inf

    # Consideration of other trucks' proximity to the customers
    customer_weights = np.zeros(len(unvisited_customers))
    for idx, customer in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, cur_truck_pos):
                continue
            customer_weights[idx] += 1 / (1 + distance(truck_pos, customer))

    # Selecting next node based on weighted shortest distance
    for index, customer in enumerate(unvisited_customers):
        dist = distance(cur_truck_pos, customer) - customer_weights[index]
        if dist < best_distance:
            best_distance = dist
            best_node = index

    return best_node
